/**
 * @param {number[]} nums
 * @param {number[][]} edges
 * @return {number}
 */
function solve(nums, edges) {
    const n = nums.length;
    const adj = Array(n).fill(0).map(() => []);
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }

    let count = 0;

    // Iterate through all non-empty subsets of nodes. 
    // There are 2^n - 1 such subsets. We use a bitmask from 1 to 2^n - 1.
    const totalSubsets = 1 << n;

    for (let mask = 1; mask < totalSubsets; mask++) {
        // 1. Check the sum of values (parity)
        let sum = 0;
        for (let i = 0; i < n; i++) {
            if ((mask >> i) & 1) {
                sum += nums[i];
            }
        }

        if (sum % 2 !== 0) {
            continue; // Sum must be even
        }

        // 2. Check for connectivity of the induced subgraph

        // Identify the nodes in the subset S
        const nodesInS = [];
        for (let i = 0; i < n; i++) {
            if ((mask >> i) & 1) {
                nodesInS.push(i);
            }
        }

        // If the subset has only one node, it is always connected.
        if (nodesInS.length === 1) {
            count++;
            continue;
        }

        // Use BFS or DFS to check connectivity among nodes in S

        const startNode = nodesInS[0];
        const visited = new Set();
        const queue = [startNode];
        visited.add(startNode);
        let visitedCount = 1;

        while (queue.length > 0) {
            const u = queue.shift();

            for (const v of adj[u]) {
                // Check if v is in S AND v has not been visited
                const isInS = (mask >> v) & 1;
                if (isInS && !visited.has(v)) {
                    visited.add(v);
                    visitedCount++;
                    queue.push(v);
                }
            }
        }

        // The subgraph is connected if the number of visited nodes equals the size of S
        if (visitedCount === nodesInS.length) {
            count++;
        }
    }

    return count;
}

